<?php
declare(strict_types=1);
function scheduled_report_next_run(string $type,?int $weekday,string $time,string $timezone,?DateTimeImmutable $after=null):DateTimeImmutable{$tz=new DateTimeZone(in_array($timezone,timezone_identifiers_list(),true)?$timezone:'America/New_York');$after=($after?:new DateTimeImmutable('now',$tz))->setTimezone($tz);[$hour,$minute]=array_map('intval',explode(':',substr($time,0,5)));if($type==='weekly_pipeline'){$day=max(1,min(7,$weekday?:1));$add=($day-(int)$after->format('N')+7)%7;$candidate=$after->setTime($hour,$minute)->modify("+$add days");if($candidate<=$after)$candidate=$candidate->modify('+7 days');return $candidate;}$candidate=$after->modify('last day of this month')->setTime($hour,$minute);if($candidate<=$after)$candidate=$after->modify('last day of next month')->setTime($hour,$minute);return $candidate;}
function scheduled_report_pipeline_body():string{$rows=db()->query("SELECT COALESCE(NULLIF(u.display_name,''),u.username,'Unassigned') owner,o.status,COUNT(*) opportunities,COALESCE(SUM(o.value),0) total_value FROM opportunities o LEFT JOIN users u ON u.id=o.owner_id WHERE o.active=1 AND o.status NOT IN ('won','lost') GROUP BY owner,o.status ORDER BY owner,o.status")->fetchAll();$due=db()->query("SELECT o.title,COALESCE(NULLIF(u.display_name,''),u.username,'Unassigned') owner,o.status,o.value,o.expected_close_date FROM opportunities o LEFT JOIN users u ON u.id=o.owner_id WHERE o.active=1 AND o.status NOT IN ('won','lost') AND o.expected_close_date<=DATE_ADD(CURRENT_DATE,INTERVAL 30 DAY) ORDER BY o.expected_close_date LIMIT 100")->fetchAll();$body="WEEKLY PIPELINE REPORT\nGenerated: ".date('F j, Y g:i A T')."\n\nPIPELINE BY OWNER AND STAGE\n";foreach($rows as $r)$body.=sprintf("%s | %s | %d opportunities | $%s\n",$r['owner'],option_label('opportunity_status',$r['status']),(int)$r['opportunities'],number_format((float)$r['total_value'],2));if(!$rows)$body.="No open opportunities.\n";$body.="\nCLOSING OR OVERDUE WITHIN 30 DAYS\n";foreach($due as $r)$body.=sprintf("%s | %s | %s | $%s | %s\n",$r['title'],$r['owner'],option_label('opportunity_status',$r['status']),number_format((float)$r['value'],2),$r['expected_close_date']?:'No date');if(!$due)$body.="No opportunities are due within 30 days.\n";return $body."\nOpen pipeline: ".rtrim((string)config('url'),'/')."/opportunities/board\n";}
function scheduled_report_contacts_body():string{$start=date('Y-m-01 00:00:00');$end=date('Y-m-01 00:00:00',strtotime('+1 month'));$q=db()->prepare("SELECT COALESCE(NULLIF(u.display_name,''),u.username,'System / API') creator,COUNT(*) contacts FROM contacts c LEFT JOIN users u ON u.id=c.created_by WHERE c.created_at>=? AND c.created_at<? GROUP BY creator ORDER BY contacts DESC,creator");$q->execute([$start,$end]);$rows=$q->fetchAll();$total=array_sum(array_map(fn($r)=>(int)$r['contacts'],$rows));$body="MONTH-END NEW CONTACTS REPORT\nPeriod: ".date('F Y')."\nGenerated: ".date('F j, Y g:i A T')."\n\nTotal contacts added: $total\n\nCONTACTS BY CREATOR\n";foreach($rows as $r)$body.=$r['creator'].' | '.(int)$r['contacts']."\n";if(!$rows)$body.="No contacts were added this month.\n";return $body."\nView contacts: ".rtrim((string)config('url'),'/')."/contacts?view=all\n";}
function scheduled_report_body(string $type):string{return $type==='monthly_new_contacts'?scheduled_report_contacts_body():scheduled_report_pipeline_body();}

